static common_chat_params common_chat_params_init_mistral_instruct_v3(const common_chat_template &          tmpl,
                                                                       const autoparser::generation_params & inputs) {
    common_chat_params data;

    // Mistral Instruct v0.3 has no dedicated system role.
    // System content is prepended to the first user turn, separated by a blank line.
    auto        adjusted_messages = json::array();
    bool        system_injected   = false;
    std::string system_text;

    for (const auto & msg : inputs.messages) {
        const auto role = msg.value("role", "");
        if (role == "system") {
            if (msg.contains("content") && msg.at("content").is_string()) {
                if (!system_text.empty()) {
                    system_text += "\n\n";
                }
                system_text += msg.at("content").get<std::string>();
            }
            // Drop the standalone system message; its text will be merged into the first user turn.
            continue;
        }
        if (!system_injected && !system_text.empty() && role == "user") {
            auto adjusted = msg;
            if (adjusted.contains("content") && adjusted.at("content").is_string()) {
                adjusted["content"] = system_text + "\n\n" + adjusted.at("content").get<std::string>();
            }
            system_injected = true;
            adjusted_messages.push_back(adjusted);
        } else {
            adjusted_messages.push_back(msg);
        }
    }

    data.prompt           = common_chat_template_direct_apply_impl(tmpl, inputs, /* messages_override = */ adjusted_messages);
    data.format           = COMMON_CHAT_FORMAT_PEG_NATIVE;
    data.supports_thinking = false;
    data.preserved_tokens  = {
        "[INST]",
        "[/INST]",
    };

    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        return p.prefix(inputs.generation_prompt) << p.content(p.rest());
    });

    data.parser = parser.save();

    return data;
}

